+import type { EventBus } from '../events/event-bus.js';
+import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
+import { Logger } from '../utils/logger.js';
+
+export interface SmsMessage {
+  id: string;
+  to: string;
+  body: string;
+  sentAt: Date;
+}
+
+let nextId = 1;
+
+function generateSmsId(): string {
+  return `sms-${String(nextId++).padStart(4, '0')}`;
+}
+
+export function resetSmsIdCounter(): void {
+  nextId = 1;
+}
+
+export class SmsChannelService {
+  private logger = new Logger('SmsChannelService');
+  private messages: SmsMessage[] = [];
+
+  constructor(private eventBus: EventBus) {
+    this.registerHandlers();
+  }
+
+  private registerHandlers(): void {
+    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
+      this.handleOrderCreated(event);
+    });
+
+    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
+      this.handleOrderStatusChanged(event);
+    });
+  }
+
+  private handleOrderCreated(event: OrderCreatedEvent): void {
+    this.logger.info(`Sending SMS for order ${event.order.id}`);
+
+    const itemCount = event.order.items.reduce((sum, item) => sum + item.quantity, 0);
+
+    this.sendSms({
+      to: event.user.id,
+      body: `Order ${event.order.id} confirmed: ${itemCount} item(s), total $${event.order.total.toFixed(2)}.`,
+    });
+  }
+
+  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
+    this.logger.info(`Sending SMS status update for order ${event.order.id}`);
+
+    this.sendSms({
+      to: event.order.userId,
+      body: `Order ${event.order.id} status: ${event.newStatus}.`,
+    });
+  }
+
+  private sendSms(params: { to: string; body: string }): void {
+    const message: SmsMessage = {
+      id: generateSmsId(),
+      to: params.to,
+      body: params.body,
+      sentAt: new Date(),
+    };
+    this.messages.push(message);
+    this.logger.info(`SMS sent: ${message.id} to ${params.to}`);
+  }
+
+  getMessages(): SmsMessage[] {
+    return [...this.messages];
+  }
+
+  getMessagesForRecipient(to: string): SmsMessage[] {
+    return this.messages.filter((m) => m.to === to);
+  }
+
+  getMessageCount(): number {
+    return this.messages.length;
+  }
+
+  clearMessages(): void {
+    this.messages = [];
+  }
+}

