+import type { EventBus } from '../events/event-bus.js';
+import type { AppEvent } from '../events/event-types.js';
+import { Logger } from '../utils/logger.js';
+
+export interface WebhookDelivery {
+  id: string;
+  url: string;
+  eventType: string;
+  payload: Record<string, unknown>;
+  deliveredAt: Date;
+}
+
+let nextId = 1;
+
+function generateDeliveryId(): string {
+  return `whk-${String(nextId++).padStart(4, '0')}`;
+}
+
+export function resetWebhookIdCounter(): void {
+  nextId = 1;
+}
+
+export class WebhookChannelService {
+  private logger = new Logger('WebhookChannelService');
+  private deliveries: WebhookDelivery[] = [];
+  private registeredUrls: Map<string, string[]> = new Map();
+
+  constructor(private eventBus: EventBus) {
+    this.registerHandlers();
+  }
+
+  private registerHandlers(): void {
+    this.eventBus.on<AppEvent>('order:created', (event) => {
+      this.deliverWebhooks(event);
+    });
+
+    this.eventBus.on<AppEvent>('order:status-changed', (event) => {
+      this.deliverWebhooks(event);
+    });
+
+    this.eventBus.on<AppEvent>('user:created', (event) => {
+      this.deliverWebhooks(event);
+    });
+
+    this.eventBus.on<AppEvent>('user:updated', (event) => {
+      this.deliverWebhooks(event);
+    });
+  }
+
+  registerWebhookUrl(eventType: string, url: string): void {
+    const urls = this.registeredUrls.get(eventType) ?? [];
+    if (!urls.includes(url)) {
+      urls.push(url);
+      this.registeredUrls.set(eventType, urls);
+    }
+  }
+
+  unregisterWebhookUrl(eventType: string, url: string): void {
+    const urls = this.registeredUrls.get(eventType) ?? [];
+    const index = urls.indexOf(url);
+    if (index >= 0) {
+      urls.splice(index, 1);
+    }
+  }
+
+  private deliverWebhooks(event: AppEvent): void {
+    const urls = this.registeredUrls.get(event.type) ?? [];
+
+    for (const url of urls) {
+      this.logger.info(`Delivering webhook for ${event.type} to ${url}`);
+
+      const delivery: WebhookDelivery = {
+        id: generateDeliveryId(),
+        url,
+        eventType: event.type,
+        payload: event as unknown as Record<string, unknown>,
+        deliveredAt: new Date(),
+      };
+      this.deliveries.push(delivery);
+      this.logger.info(`Webhook delivered: ${delivery.id} to ${url}`);
+    }
+  }
+
+  getDeliveries(): WebhookDelivery[] {
+    return [...this.deliveries];
+  }
+
+  getDeliveriesForUrl(url: string): WebhookDelivery[] {
+    return this.deliveries.filter((d) => d.url === url);
+  }
+
+  getDeliveryCount(): number {
+    return this.deliveries.length;
+  }
+
+  clearDeliveries(): void {
+    this.deliveries = [];
+  }
+}

