import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import { Logger } from '../utils/logger.js';

export interface SmsMessage {
  id: string;
  to: string;
  body: string;
  sentAt: Date;
}

let nextId = 1;

function generateSmsId(): string {
  return `sms-${String(nextId++).padStart(4, '0')}`;
}

export function resetSmsIdCounter(): void {
  nextId = 1;
}

export class SmsChannelService {
  private logger = new Logger('SmsChannelService');
  private messages: SmsMessage[] = [];

  constructor(private eventBus: EventBus) {
    this.registerHandlers();
  }

  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  private handleOrderCreated(event: OrderCreatedEvent): void {
    this.logger.info(`Sending SMS for order ${event.order.id}`);

    const itemCount = event.order.items.reduce((sum, item) => sum + item.quantity, 0);

    this.sendSms({
      to: event.user.id,
      body: `Order ${event.order.id} confirmed: ${itemCount} item(s), total $${event.order.total.toFixed(2)}.`,
    });
  }

  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    this.logger.info(`Sending SMS status update for order ${event.order.id}`);

    this.sendSms({
      to: event.order.userId,
      body: `Order ${event.order.id} status: ${event.newStatus}.`,
    });
  }

  private sendSms(params: { to: string; body: string }): void {
    const message: SmsMessage = {
      id: generateSmsId(),
      to: params.to,
      body: params.body,
      sentAt: new Date(),
    };
    this.messages.push(message);
    this.logger.info(`SMS sent: ${message.id} to ${params.to}`);
  }

  getMessages(): SmsMessage[] {
    return [...this.messages];
  }

  getMessagesForRecipient(to: string): SmsMessage[] {
    return this.messages.filter((m) => m.to === to);
  }

  getMessageCount(): number {
    return this.messages.length;
  }

  clearMessages(): void {
    this.messages = [];
  }
}

import type { EventBus } from '../events/event-bus.js';
import type { AppEvent } from '../events/event-types.js';
import { Logger } from '../utils/logger.js';

export interface WebhookDelivery {
  id: string;
  url: string;
  eventType: string;
  payload: Record<string, unknown>;
  deliveredAt: Date;
}

let nextId = 1;

function generateDeliveryId(): string {
  return `whk-${String(nextId++).padStart(4, '0')}`;
}

export function resetWebhookIdCounter(): void {
  nextId = 1;
}

export class WebhookChannelService {
  private logger = new Logger('WebhookChannelService');
  private deliveries: WebhookDelivery[] = [];
  private registeredUrls: Map<string, string[]> = new Map();

  constructor(private eventBus: EventBus) {
    this.registerHandlers();
  }

  private registerHandlers(): void {
    this.eventBus.on<AppEvent>('order:created', (event) => {
      this.deliverWebhooks(event);
    });

    this.eventBus.on<AppEvent>('order:status-changed', (event) => {
      this.deliverWebhooks(event);
    });

    this.eventBus.on<AppEvent>('user:created', (event) => {
      this.deliverWebhooks(event);
    });

    this.eventBus.on<AppEvent>('user:updated', (event) => {
      this.deliverWebhooks(event);
    });
  }

  registerWebhookUrl(eventType: string, url: string): void {
    const urls = this.registeredUrls.get(eventType) ?? [];
    if (!urls.includes(url)) {
      urls.push(url);
      this.registeredUrls.set(eventType, urls);
    }
  }

  unregisterWebhookUrl(eventType: string, url: string): void {
    const urls = this.registeredUrls.get(eventType) ?? [];
    const index = urls.indexOf(url);
    if (index >= 0) {
      urls.splice(index, 1);
    }
  }

  private deliverWebhooks(event: AppEvent): void {
    const urls = this.registeredUrls.get(event.type) ?? [];

    for (const url of urls) {
      this.logger.info(`Delivering webhook for ${event.type} to ${url}`);

      const delivery: WebhookDelivery = {
        id: generateDeliveryId(),
        url,
        eventType: event.type,
        payload: event as unknown as Record<string, unknown>,
        deliveredAt: new Date(),
      };
      this.deliveries.push(delivery);
      this.logger.info(`Webhook delivered: ${delivery.id} to ${url}`);
    }
  }

  getDeliveries(): WebhookDelivery[] {
    return [...this.deliveries];
  }

  getDeliveriesForUrl(url: string): WebhookDelivery[] {
    return this.deliveries.filter((d) => d.url === url);
  }

  getDeliveryCount(): number {
    return this.deliveries.length;
  }

  clearDeliveries(): void {
    this.deliveries = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  SmsChannelService,
  resetSmsIdCounter,
} from '../../src/services/sms-channel.service.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('SmsChannelService', () => {
  let eventBus: EventBus;
  let service: SmsChannelService;

  beforeEach(() => {
    eventBus = new EventBus();
    service = new SmsChannelService(eventBus);
    resetSmsIdCounter();
  });

  describe('order:created handler', () => {
    it('should send SMS on order created', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          ],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const messages = service.getMessages();
      expect(messages).toHaveLength(1);
      expect(messages[0]?.to).toBe('user-1');
      expect(messages[0]?.body).toContain('order-1');
      expect(messages[0]?.body).toContain('2 item(s)');
      expect(messages[0]?.body).toContain('$20.00');
    });

    it('should count total items across all line items', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
            { productId: 'p2', name: 'Gadget', quantity: 3, unitPrice: 5 },
          ],
          total: 35,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const messages = service.getMessages();
      expect(messages[0]?.body).toContain('5 item(s)');
    });
  });

  describe('order:status-changed handler', () => {
    it('should send SMS on status change', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const messages = service.getMessages();
      expect(messages).toHaveLength(1);
      expect(messages[0]?.to).toBe('user-1');
      expect(messages[0]?.body).toContain('confirmed');
    });
  });

  describe('message management', () => {
    it('should count messages', async () => {
      expect(service.getMessageCount()).toBe(0);

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      expect(service.getMessageCount()).toBe(1);
    });

    it('should filter by recipient', async () => {
      await eventBus.emit({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
          ],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      });

      expect(service.getMessagesForRecipient('user-1')).toHaveLength(1);
      expect(service.getMessagesForRecipient('user-2')).toHaveLength(0);
    });

    it('should clear messages', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      service.clearMessages();
      expect(service.getMessageCount()).toBe(0);
    });

    it('should generate sequential SMS IDs', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-2',
          userId: 'user-1',
          items: [],
          total: 30,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      });

      const messages = service.getMessages();
      expect(messages[0]?.id).toBe('sms-0001');
      expect(messages[1]?.id).toBe('sms-0002');
    });
  });
});

